const cards = root_element.querySelectorAll('.dashboard-card');

// bind clicks
cards.forEach(card => {
  card.addEventListener('click', () => {
    const doctype = card.getAttribute('data-doctype');
    const report = card.getAttribute('data-report');
    const page = card.getAttribute('data-page');
    const doctypereport = card.getAttribute('data-doctypereport');

    if (doctype && typeof specialReportDoctypes !== "undefined" && specialReportDoctypes[doctype]) {
      // override default for special doctypes
      frappe.set_route('query-report', specialReportDoctypes[doctype]);
    } else if (doctype) {
      frappe.set_route('List', doctype);
    } else if (report) {
      frappe.set_route('query-report', report);
    } else if (page) {
      frappe.set_route('Tree', page);
    } else if (doctypereport) {
      frappe.set_route('query-report', doctypereport);
    }
  });

  // live count fetch
  const doctype = card.getAttribute('data-doctype');
  const countSpan = card.querySelector('span');

  if (doctype && countSpan) {
    frappe.call({
      method: 'frappe.desk.reportview.get_count',
      args: { doctype: doctype, filters: [] },  // add filters if needed
      callback: function (r) {
        countSpan.textContent = (r && r.message) ? r.message : "0";
      }
    });
  }

  // make it look clickable
  card.style.cursor = "pointer";
});

