/* Section Titles */
.section-title {
    font-size: 28px;
    font-weight: 700;
    color: #212529;
    margin-bottom: 24px;
}

/* Grid Layout */
.row {
    display: flex;
    flex-wrap: wrap;
    margin-right: -15px;
    margin-left: -15px;
}

.g-4 {
    gap: 16px;
