    background: linear-gradient(to bottom right, rgba(239, 246, 255, 0.3), rgba(219, 234, 254, 0.3));
    border: 1px solid rgba(191, 219, 254, 0.3);
    border-radius: 16px;
    padding: 32px;
    margin-bottom: 32px;
}

